'use client'

import { useState } from 'react'
import { useRouter } from 'next/navigation'

type Step = 1 | 2 | 3 | 4

export default function CreateAgentWizardPage() {
  const router = useRouter()
  const [step, setStep] = useState<Step>(1)
  const [loading, setLoading] = useState(false)

  // Step 1: Business Info
  const [businessName, setBusinessName] = useState('')
  const [industry, setIndustry] = useState('')
  const [products, setProducts] = useState('')

  // Step 2: Knowledge Base
  const [kbMethod, setKbMethod] = useState<'url' | 'manual' | 'upload'>('manual')
  const [kbUrl, setKbUrl] = useState('')
  const [kbText, setKbText] = useState('')

  // Step 3: Personality
  const [agentName, setAgentName] = useState('')
  const [tone, setTone] = useState('professional')
  const [activeHoursStart, setActiveHoursStart] = useState('09')
  const [activeHoursEnd, setActiveHoursEnd] = useState('21')

  // Step 4: Channels
  const [selectedChannels, setSelectedChannels] = useState<string[]>(['whatsapp'])
  const [modelTier, setModelTier] = useState('balanced')

  const industries = [
    'Retail',
    'E-commerce',
    'Healthcare',
    'Education',
    'Finance',
    'Real Estate',
    'Hospitality',
    'SaaS',
    'Other',
  ]

  const handleNext = async () => {
    if (step === 1 && (!businessName || !industry)) {
      alert('Please fill in all fields')
      return
    }
    if (step === 4) {
      // Submit form
      setLoading(true)
      try {
        const response = await fetch('/api/agents', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            name: agentName || businessName,
            businessName,
            industry,
            products,
            knowledgeBase: {
              method: kbMethod,
              url: kbUrl,
              content: kbText,
            },
            tone,
            activeHours: { start: activeHoursStart, end: activeHoursEnd },
            channels: selectedChannels,
            modelTier,
          }),
        })

        if (response.ok) {
          const agent = await response.json()
          router.push(`/agents/${agent.id}?success=true`)
        } else {
          alert('Failed to create agent')
        }
      } catch (_) {
        alert('Error creating agent')
        setLoading(false)
      }
      return
    }
    setStep((step + 1) as Step)
  }

  const handleBack = () => {
    if (step > 1) setStep((step - 1) as Step)
  }

  const canContinue = () => {
    if (step === 1) return businessName && industry
    if (step === 2) return kbMethod === 'manual' || kbUrl || kbText
    if (step === 3) return agentName
    return selectedChannels.length > 0
  }

  return (
    <div className="max-w-2xl mx-auto">
      {/* Progress Indicator */}
      <div className="mb-8">
        <div className="flex gap-2 mb-4">
          {[1, 2, 3, 4].map((s) => (
            <div
              key={s}
              className={`flex-1 h-2 rounded-full ${
                s <= step ? 'bg-blue-600' : 'bg-gray-200'
              }`}
            />
          ))}
        </div>
        <p className="text-sm text-gray-600">Step {step} of 4</p>
      </div>

      {/* Step 1: Business Info */}
      {step === 1 && (
        <div>
          <h2 className="text-2xl font-bold text-gray-900 mb-2">About Your Business</h2>
          <p className="text-gray-600 mb-6">Help us understand your business context</p>

          <div className="space-y-4">
            <div>
              <label className="block text-sm font-medium text-gray-900 mb-1">
                Business Name
              </label>
              <input
                type="text"
                value={businessName}
                onChange={(e) => setBusinessName(e.target.value)}
                placeholder="e.g., Sharma's Dental Clinic"
                className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
              />
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-900 mb-1">
                Industry
              </label>
              <select
                value={industry}
                onChange={(e) => setIndustry(e.target.value)}
                className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
              >
                <option value="">Select industry</option>
                {industries.map((ind) => (
                  <option key={ind} value={ind}>
                    {ind}
                  </option>
                ))}
              </select>
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-900 mb-1">
                Main Products/Services
              </label>
              <textarea
                value={products}
                onChange={(e) => setProducts(e.target.value)}
                placeholder="e.g., General dentistry, orthodontics, teeth whitening"
                rows={3}
                className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
              />
            </div>
          </div>
        </div>
      )}

      {/* Step 2: Knowledge Base */}
      {step === 2 && (
        <div>
          <h2 className="text-2xl font-bold text-gray-900 mb-2">Business Knowledge Base</h2>
          <p className="text-gray-600 mb-6">Teach your agent about your business</p>

          <div className="space-y-4">
            {/* Method Selector */}
            <div className="space-y-3">
              {['manual', 'url', 'upload'].map((method) => (
                <label key={method} className="flex items-center gap-3 p-3 border border-gray-300 rounded-lg cursor-pointer hover:bg-gray-50">
                  <input
                    type="radio"
                    name="kb-method"
                    value={method}
                    checked={kbMethod === method}
                    onChange={(e) => setKbMethod(e.target.value as typeof kbMethod)}
                    className="w-4 h-4"
                  />
                  <div>
                    <p className="font-medium text-gray-900">
                      {method === 'manual' && 'Type FAQs'}
                      {method === 'url' && 'Scrape from Website'}
                      {method === 'upload' && 'Upload PDF/Docs'}
                    </p>
                    <p className="text-sm text-gray-600">
                      {method === 'manual' && 'Enter information manually'}
                      {method === 'url' && 'Automatically extract from your website'}
                      {method === 'upload' && 'Upload your business documents'}
                    </p>
                  </div>
                </label>
              ))}
            </div>

            {/* Content based on method */}
            {kbMethod === 'manual' && (
              <textarea
                value={kbText}
                onChange={(e) => setKbText(e.target.value)}
                placeholder="Enter FAQs, procedures, policies, or any info your agent should know..."
                rows={6}
                className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
              />
            )}

            {kbMethod === 'url' && (
              <input
                type="url"
                value={kbUrl}
                onChange={(e) => setKbUrl(e.target.value)}
                placeholder="https://your-website.com"
                className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
              />
            )}

            {kbMethod === 'upload' && (
              <div className="border-2 border-dashed border-gray-300 rounded-lg p-8 text-center">
                <p className="text-gray-600">Drag & drop PDFs or docs here</p>
                <input type="file" multiple className="hidden" />
              </div>
            )}
          </div>
        </div>
      )}

      {/* Step 3: Personality */}
      {step === 3 && (
        <div>
          <h2 className="text-2xl font-bold text-gray-900 mb-2">Agent Personality</h2>
          <p className="text-gray-600 mb-6">Define how your agent behaves</p>

          <div className="space-y-4">
            <div>
              <label className="block text-sm font-medium text-gray-900 mb-1">
                Agent Name
              </label>
              <input
                type="text"
                value={agentName}
                onChange={(e) => setAgentName(e.target.value)}
                placeholder="e.g., Dr. Smile, Support Agent"
                className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
              />
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-900 mb-1">
                Communication Tone
              </label>
              <select
                value={tone}
                onChange={(e) => setTone(e.target.value)}
                className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
              >
                <option value="professional">Professional</option>
                <option value="friendly">Friendly</option>
                <option value="casual">Casual</option>
                <option value="formal">Formal</option>
              </select>
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-900 mb-1">
                Active Hours (IST)
              </label>
              <div className="flex gap-2 items-center">
                <input
                  type="number"
                  min="0"
                  max="23"
                  value={activeHoursStart}
                  onChange={(e) => setActiveHoursStart(e.target.value)}
                  className="w-20 px-3 py-2 border border-gray-300 rounded-lg"
                />
                <span>to</span>
                <input
                  type="number"
                  min="0"
                  max="23"
                  value={activeHoursEnd}
                  onChange={(e) => setActiveHoursEnd(e.target.value)}
                  className="w-20 px-3 py-2 border border-gray-300 rounded-lg"
                />
                <span className="text-sm text-gray-600">(24-hour format)</span>
              </div>
              <p className="text-xs text-gray-500 mt-2">Default: 9am - 9pm</p>
            </div>
          </div>
        </div>
      )}

      {/* Step 4: Channels & AI Model */}
      {step === 4 && (
        <div>
          <h2 className="text-2xl font-bold text-gray-900 mb-2">Channels & AI Model</h2>
          <p className="text-gray-600 mb-6">Choose communication channels and AI intelligence</p>

          <div className="space-y-6">
            {/* Channels */}
            <div>
              <label className="block text-sm font-medium text-gray-900 mb-3">
                Communication Channels
              </label>
              <div className="space-y-2">
                {['whatsapp', 'email', 'sms', 'phone'].map((channel) => (
                  <label key={channel} className="flex items-center gap-3 p-3 border border-gray-200 rounded-lg cursor-pointer hover:bg-gray-50">
                    <input
                      type="checkbox"
                      checked={selectedChannels.includes(channel)}
                      onChange={(e) => {
                        if (e.target.checked) {
                          setSelectedChannels([...selectedChannels, channel])
                        } else {
                          setSelectedChannels(selectedChannels.filter((c) => c !== channel))
                        }
                      }}
                      className="w-4 h-4"
                    />
                    <span className="font-medium text-gray-900">
                      {channel.charAt(0).toUpperCase() + channel.slice(1)}
                    </span>
                  </label>
                ))}
              </div>
            </div>

            {/* AI Model */}
            <div>
              <label className="block text-sm font-medium text-gray-900 mb-3">
                AI Intelligence Level
              </label>
              <div className="space-y-2">
                {[
                  { id: 'fast', name: 'Fast & Free', desc: 'Groq Llama - instant, no cost' },
                  { id: 'balanced', name: 'Balanced', desc: 'Gemini 2.0 Flash - smart & free' },
                  { id: 'smart', name: 'Smartest', desc: 'Claude/GPT - most capable (paid)' },
                ].map((model) => (
                  <label key={model.id} className={`flex items-start gap-3 p-3 border rounded-lg cursor-pointer ${
                    modelTier === model.id ? 'border-blue-600 bg-blue-50' : 'border-gray-200 hover:bg-gray-50'
                  }`}>
                    <input
                      type="radio"
                      name="model"
                      value={model.id}
                      checked={modelTier === model.id}
                      onChange={(e) => setModelTier(e.target.value)}
                      className="w-4 h-4 mt-1"
                    />
                    <div>
                      <p className="font-medium text-gray-900">{model.name}</p>
                      <p className="text-sm text-gray-600">{model.desc}</p>
                    </div>
                  </label>
                ))}
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Navigation Buttons */}
      <div className="mt-8 flex gap-4">
        <button
          onClick={handleBack}
          disabled={step === 1}
          className="px-6 py-3 border border-gray-300 text-gray-900 rounded-lg hover:bg-gray-50 font-medium disabled:opacity-50 disabled:cursor-not-allowed"
        >
          ← Back
        </button>

        <button
          onClick={handleNext}
          disabled={!canContinue() || loading}
          className={`flex-1 py-3 rounded-lg font-medium text-white transition-colors ${
            canContinue() && !loading
              ? 'bg-blue-600 hover:bg-blue-700'
              : 'bg-gray-400 cursor-not-allowed'
          }`}
        >
          {step === 4 ? (loading ? 'Creating...' : 'Deploy Agent') : 'Continue →'}
        </button>
      </div>
    </div>
  )
}

'use client'

import { useState, useEffect } from 'react'
import { useRouter, useSearchParams } from 'next/navigation'
import { useUser } from '@clerk/nextjs'

type PaymentMethod = 'stripe' | 'razorpay' | null

export default function CheckoutPage() {
  const router = useRouter()
  const searchParams = useSearchParams()
  const { user } = useUser()

  const tier = searchParams.get('tier')
  const currency = searchParams.get('currency') || 'INR'
  const [paymentMethod, setPaymentMethod] = useState<PaymentMethod>(null)
  const [loading, setLoading] = useState(false)

  useEffect(() => {
    if (!tier) {
      router.push('/create-agent')
    }
  }, [tier, router])

  const tierConfig = {
    intern: { name: 'Intern', priceINR: 999, priceUSD: 12 },
    agent: { name: 'Agent', priceINR: 2499, priceUSD: 30 },
  }

  const config = tierConfig[tier as keyof typeof tierConfig]
  if (!config) return null

  const price = currency === 'INR' ? config.priceINR : config.priceUSD
  const currencySymbol = currency === 'INR' ? '₹' : '$'

  const handleStripePayment = async () => {
    setLoading(true)
    try {
      const response = await fetch('/api/checkout/stripe', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          tier,
          currency,
          email: user?.emailAddresses[0]?.emailAddress,
        }),
      })

      const data = await response.json()
      if (data.url) {
        window.location.href = data.url
      }
    } catch (error) {
      console.error('Stripe error:', error)
      alert('Payment initiation failed. Please try again.')
      setLoading(false)
    }
  }

  const handleRazorpayPayment = async () => {
    setLoading(true)
    try {
      const response = await fetch('/api/checkout/razorpay', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          tier,
          amount: price * 100, // Razorpay uses paise
          email: user?.emailAddresses[0]?.emailAddress,
        }),
      })

      const data = await response.json()

      // Load Razorpay script and initiate payment
      const script = document.createElement('script')
      script.src = 'https://checkout.razorpay.com/v1/checkout.js'
      script.onload = () => {
        const options = {
          key: process.env.NEXT_PUBLIC_RAZORPAY_KEY_ID,
          amount: data.amount,
          currency: 'INR',
          order_id: data.orderId,
          name: 'diyaa.ai',
          description: `${config.name} Plan - 7 Days Free Trial`,
          image: '/logo.png',
          handler: async (response: any) => {
            // Verify payment on backend
            await fetch('/api/checkout/razorpay/verify', {
              method: 'POST',
              headers: { 'Content-Type': 'application/json' },
              body: JSON.stringify({
                razorpay_order_id: response.razorpay_order_id,
                razorpay_payment_id: response.razorpay_payment_id,
                razorpay_signature: response.razorpay_signature,
                tier,
              }),
            })
            router.push(`/dashboard?success=true&tier=${tier}`)
          },
          prefill: {
            email: user?.emailAddresses[0]?.emailAddress,
            name: user?.fullName,
          },
          theme: { color: '#0284c7' },
        }
        const razorpay = new (window as any).Razorpay(options)
        razorpay.open()
      }
      document.body.appendChild(script)
    } catch (error) {
      console.error('Razorpay error:', error)
      alert('Payment initiation failed. Please try again.')
      setLoading(false)
    }
  }

  return (
    <div className="max-w-2xl mx-auto">
      <div className="mb-8">
        <h1 className="text-3xl font-bold text-gray-900 mb-2">Complete Your Purchase</h1>
        <p className="text-gray-600">7-day free trial. No credit card charges until the trial ends.</p>
      </div>

      {/* Order Summary */}
      <div className="bg-white border border-gray-200 rounded-lg p-6 mb-8">
        <h2 className="text-lg font-bold text-gray-900 mb-4">Order Summary</h2>

        <div className="space-y-3 mb-6 pb-6 border-b border-gray-200">
          <div className="flex justify-between text-gray-700">
            <span>{config.name} Plan (Monthly)</span>
            <span className="font-bold">{currencySymbol}{price}</span>
          </div>
          <div className="flex justify-between text-sm text-gray-600">
            <span>Trial Period</span>
            <span>7 days free</span>
          </div>
          <div className="flex justify-between text-sm text-gray-600">
            <span>Auto-renews on</span>
            <span>Day 8</span>
          </div>
        </div>

        <div className="flex justify-between text-lg font-bold text-gray-900">
          <span>Total</span>
          <span>{currencySymbol}{price}/month after trial</span>
        </div>
      </div>

      {/* Payment Method Selection */}
      <div className="mb-8">
        <h2 className="text-lg font-bold text-gray-900 mb-4">Choose Payment Method</h2>

        <div className="space-y-4">
          {/* Stripe */}
          <div
            onClick={() => setPaymentMethod('stripe')}
            className={`p-4 rounded-lg border-2 cursor-pointer transition-all ${
              paymentMethod === 'stripe'
                ? 'border-blue-600 bg-blue-50'
                : 'border-gray-200 hover:border-gray-300'
            }`}
          >
            <div className="flex items-center justify-between">
              <div className="flex items-center gap-3">
                <div className={`w-5 h-5 rounded-full border-2 flex items-center justify-center ${
                  paymentMethod === 'stripe' ? 'border-blue-600' : 'border-gray-400'
                }`}>
                  {paymentMethod === 'stripe' && (
                    <div className="w-3 h-3 rounded-full bg-blue-600" />
                  )}
                </div>
                <div>
                  <div className="font-bold text-gray-900">Pay with Stripe</div>
                  <div className="text-sm text-gray-600">Credit card, Apple Pay, Google Pay</div>
                </div>
              </div>
              <span className="text-2xl">💳</span>
            </div>
          </div>

          {/* Razorpay (only for INR) */}
          {currency === 'INR' && (
            <div
              onClick={() => setPaymentMethod('razorpay')}
              className={`p-4 rounded-lg border-2 cursor-pointer transition-all ${
                paymentMethod === 'razorpay'
                  ? 'border-blue-600 bg-blue-50'
                  : 'border-gray-200 hover:border-gray-300'
              }`}
            >
              <div className="flex items-center justify-between">
                <div className="flex items-center gap-3">
                  <div className={`w-5 h-5 rounded-full border-2 flex items-center justify-center ${
                    paymentMethod === 'razorpay' ? 'border-blue-600' : 'border-gray-400'
                  }`}>
                    {paymentMethod === 'razorpay' && (
                      <div className="w-3 h-3 rounded-full bg-blue-600" />
                    )}
                  </div>
                  <div>
                    <div className="font-bold text-gray-900">Pay with Razorpay</div>
                    <div className="text-sm text-gray-600">UPI, Cards, Wallets, Net Banking</div>
                  </div>
                </div>
                <span className="text-2xl">₹</span>
              </div>
            </div>
          )}
        </div>
      </div>

      {/* Pay Button */}
      <button
        onClick={
          paymentMethod === 'stripe' ? handleStripePayment : handleRazorpayPayment
        }
        disabled={!paymentMethod || loading}
        className={`w-full py-3 rounded-lg font-bold text-white transition-colors ${
          paymentMethod && !loading
            ? 'bg-blue-600 hover:bg-blue-700 cursor-pointer'
            : 'bg-gray-400 cursor-not-allowed'
        }`}
      >
        {loading ? 'Processing...' : `Start 7-Day Free Trial`}
      </button>

      {/* Security Note */}
      <div className="mt-6 text-center text-sm text-gray-600">
        <p>🔒 Your payment information is secure and encrypted</p>
        <p className="mt-2">By proceeding, you agree to our Terms of Service and Privacy Policy</p>
      </div>
    </div>
  )
}

"use client";

import { ReactNode, useState, useEffect } from "react";
import Link from "next/link";
import { usePathname, useRouter } from "next/navigation";
import { UserButton, useAuth } from "@clerk/nextjs";

const sidebarItems = [
  { name: "Your Agents", href: "/agents", icon: "🤖" },
  { name: "Agent Store", href: "/store", icon: "🏪" },
  { name: "Workflows", href: "/workflows/task-assignment", icon: "⚙️🔄" },
  { name: "Skills", href: "/skills", icon: "⚡" },
  { name: "Projects", href: "/projects", icon: "📁" },
  { name: "Contacts", href: "/contacts", icon: "👥" },
  { name: "Inbox", href: "/inbox", icon: "📬" },
  { name: "Academy", href: "/academy", icon: "📚" },
  { name: "Analytics", href: "/analytics", icon: "📊" },
  { name: "Billing", href: "/billing", icon: "💳" },
  { name: "Settings", href: "/settings", icon: "⚙️" },
];

export default function DashboardLayout({ children }: { children: ReactNode }) {
  const pathname = usePathname();
  const router = useRouter();
  const { isLoaded, isSignedIn } = useAuth();
  const [isPaused, setIsPaused] = useState(false);

  useEffect(() => {
    if (isLoaded && !isSignedIn) {
      router.push("/sign-in");
    }
  }, [isLoaded, isSignedIn, router]);

  if (!isLoaded || !isSignedIn) {
    return (
      <div className="flex h-screen items-center justify-center" style={{ background: '#0c0c0d' }}>
        <div style={{ color: '#71717a' }}>Loading...</div>
      </div>
    );
  }

  const handlePauseAll = async () => {
    setIsPaused(!isPaused);
    // TODO: Call API to pause/resume all agents
  };

  const getBreadcrumbs = () => {
    const parts = pathname.split("/").filter(Boolean);
    return parts.map((part, index) => {
      const href = "/" + parts.slice(0, index + 1).join("/");
      const name = part.charAt(0).toUpperCase() + part.slice(1);
      return { name, href };
    });
  };

  const breadcrumbs = getBreadcrumbs();

  return (
    <div className="flex h-screen" style={{ background: '#0c0c0d' }}>
      {/* Sidebar */}
      <div className="w-64 border-r flex flex-col" style={{ borderColor: 'rgba(255,255,255,0.08)', background: '#0c0c0d' }}>
        {/* Logo */}
        <div className="p-6 border-b" style={{ borderColor: 'rgba(255,255,255,0.08)' }}>
          <Link href="/dashboard" className="flex items-center gap-2">
            <div className="text-2xl font-bold" style={{ color: '#e879f9' }}>diyaa.ai</div>
          </Link>
        </div>

        {/* Navigation */}
        <nav className="flex-1 overflow-y-auto px-4 py-6">
          <ul className="space-y-2">
            {sidebarItems.map((item) => {
              const isActive = pathname === item.href || pathname.startsWith(item.href + "/");
              return (
                <li key={item.href}>
                  <Link
                    href={item.href}
                    className={`flex items-center gap-3 px-4 py-2 rounded-lg transition-colors font-medium`}
                    style={{
                      background: isActive ? 'rgba(232,121,249,0.15)' : 'transparent',
                      color: isActive ? '#e879f9' : '#71717a'
                    }}
                  >
                    <span className="text-lg">{item.icon}</span>
                    <span className="text-sm">{item.name}</span>
                  </Link>
                </li>
              );
            })}
          </ul>
        </nav>

        {/* User Profile */}
        <div className="p-4 border-t" style={{ borderColor: 'rgba(255,255,255,0.08)' }}>
          <div className="flex items-center justify-between p-2">
            <span className="text-xs font-medium" style={{ color: '#71717a' }}>Account</span>
            <UserButton afterSignOutUrl="/" />
          </div>
        </div>
      </div>

      {/* Main Content */}
      <div className="flex-1 flex flex-col overflow-hidden">
        {/* Header */}
        <header className="border-b px-6 py-4" style={{ borderColor: 'rgba(255,255,255,0.08)', background: 'rgba(22,22,24,0.4)', backdropFilter: 'blur(10px)' }}>
          <div className="flex items-center justify-between">
            {/* Breadcrumb */}
            <div className="flex items-center gap-2 text-sm">
              <Link href="/" style={{ color: '#71717a' }} className="hover:text-gray-300 transition">
                Dashboard
              </Link>
              {breadcrumbs.length > 0 && <span style={{ color: '#71717a' }}>/</span>}
              {breadcrumbs.map((crumb, index) => (
                <div key={crumb.href} className="flex items-center gap-2">
                  {index > 0 && <span style={{ color: '#71717a' }}>/</span>}
                  <Link href={crumb.href} style={{ color: '#71717a' }} className="hover:text-gray-300 transition">
                    {crumb.name}
                  </Link>
                </div>
              ))}
            </div>

            {/* Kill Switch */}
            <button onClick={handlePauseAll} className="px-4 py-2 rounded-lg hover:opacity-90 font-medium text-sm flex items-center gap-2 transition" style={{ background: '#dc2626', color: '#fff' }}>
              <span>{isPaused ? '▶' : '⏸'}</span>
              {isPaused ? 'Resume All' : 'Pause All'}
            </button>
          </div>
        </header>

        {/* Content Area */}
        <main className="flex-1 overflow-auto" style={{ background: '#0c0c0d' }}>
          <div className="p-6">{children}</div>
        </main>
      </div>
    </div>
  );
}

'use client'

import { useState, useEffect, useRef, useCallback } from 'react'
import { useParams, useRouter, useSearchParams } from 'next/navigation'
import { useUser } from '@clerk/nextjs'
import Script from 'next/script'

interface Message {
  role: 'user' | 'assistant'
  content: string
}

interface AgentConfig {
  businessName: string
  industry: string
  products: string
  targetCustomers: string
  tone: string
  language: string
  agentPersonality: string
  activeHours: string
  keyInstructions: string
  agentName: string
}

const PLAN_PRICES = {
  intern: { inr: 999, usd: 25, label: 'Intern Plan' },
  agent: { inr: 2499, usd: 50, label: 'Agent Plan' },
}

function extractAgentConfig(text: string): AgentConfig | null {
  const match = text.match(/```AGENT_CONFIG\n([\s\S]*?)```/)
  if (!match) return null
  try {
    return JSON.parse(match[1]) as AgentConfig
  } catch {
    return null
  }
}

function stripConfigBlock(text: string): string {
  return text.replace(/```AGENT_CONFIG\n[\s\S]*?```/, '').trim()
}

// Declare Razorpay on window
declare global {
  interface Window {
    Razorpay: new (options: Record<string, unknown>) => { open(): void }
  }
}

export default function OnboardPage() {
  const params = useParams()
  const searchParams = useSearchParams()
  const router = useRouter()
  const { user } = useUser()

  const agentId = params.agentId as string
  const agentName = searchParams.get('name') || agentId
  const agentIcon = searchParams.get('icon') || '🤖'
  const selectedPlan = (searchParams.get('plan') || 'agent') as 'intern' | 'agent'

  const [messages, setMessages] = useState<Message[]>([])
  const [input, setInput] = useState('')
  const [isStreaming, setIsStreaming] = useState(false)
  const [agentConfig, setAgentConfig] = useState<AgentConfig | null>(null)
  const [isDeploying, setIsDeploying] = useState(false)
  const [questionCount, setQuestionCount] = useState(0)
  const [razorpayLoaded, setRazorpayLoaded] = useState(false)
  const messagesEndRef = useRef<HTMLDivElement>(null)
  const inputRef = useRef<HTMLInputElement>(null)
  const streamingMessageRef = useRef('')

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' })
  }

  useEffect(() => {
    scrollToBottom()
  }, [messages])

  // Start interview on mount
  useEffect(() => {
    startInterview()
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [])

  const streamResponse = useCallback(async (userMessages: Message[]) => {
    setIsStreaming(true)
    streamingMessageRef.current = ''

    // Add empty assistant message placeholder
    setMessages(prev => [...prev, { role: 'assistant', content: '' }])

    try {
      const res = await fetch('/api/onboard/interview', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ agentType: agentName, messages: userMessages }),
      })

      if (!res.body) throw new Error('No response body')

      const reader = res.body.getReader()
      const decoder = new TextDecoder()
      let buffer = ''

      while (true) {
        const { done, value } = await reader.read()
        if (done) break

        buffer += decoder.decode(value, { stream: true })
        const lines = buffer.split('\n')
        buffer = lines.pop() || ''

        for (const line of lines) {
          if (!line.startsWith('data: ')) continue
          const data = line.slice(6)
          if (data === '[DONE]') continue
          try {
            const parsed = JSON.parse(data) as { token?: string; error?: string }
            if (parsed.token) {
              streamingMessageRef.current += parsed.token
              const fullText = streamingMessageRef.current

              // Update the last message in real-time
              setMessages(prev => {
                const updated = [...prev]
                updated[updated.length - 1] = {
                  role: 'assistant',
                  content: fullText,
                }
                return updated
              })
            }
          } catch {
            // skip
          }
        }
      }

      // Check if config is complete
      const finalText = streamingMessageRef.current
      const config = extractAgentConfig(finalText)
      if (config) {
        setAgentConfig(config)
        // Clean the display message
        setMessages(prev => {
          const updated = [...prev]
          updated[updated.length - 1] = {
            role: 'assistant',
            content: stripConfigBlock(finalText),
          }
          return updated
        })
      }

    } catch (err) {
      setMessages(prev => {
        const updated = [...prev]
        updated[updated.length - 1] = {
          role: 'assistant',
          content: 'Sorry, I had a connection issue. Please try again.',
        }
        return updated
      })
    } finally {
      setIsStreaming(false)
      inputRef.current?.focus()
    }
  }, [agentName])

  const startInterview = useCallback(async () => {
    await streamResponse([])
    setQuestionCount(1)
  }, [streamResponse])

  const sendMessage = async () => {
    if (!input.trim() || isStreaming) return

    const userMessage: Message = { role: 'user', content: input.trim() }
    const newMessages = [...messages, userMessage]
    setMessages(newMessages)
    setInput('')
    setQuestionCount(q => q + 1)

    // Only send user messages to API (exclude streaming placeholders)
    const apiMessages = newMessages.filter(m => m.content.length > 0)
    await streamResponse(apiMessages)
  }

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault()
      sendMessage()
    }
  }

  const handleQuickDeploy = async () => {
    if (!user || !agentConfig) return
    setIsDeploying(true)

    // Open Razorpay
    if (!razorpayLoaded || !window.Razorpay) {
      // Fallback to Stripe or direct deploy if Razorpay not loaded
      await deployAgent()
      return
    }

    const plan = PLAN_PRICES[selectedPlan]

    // First create the agent to get agentId, then open payment
    // This ensures webhook has agentId in notes
    const agentRes = await fetch('/api/onboard/deploy', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        agentType: agentName,
        agentIcon,
        config: agentConfig,
        userId: user.id,
        plan: selectedPlan,
        skipPayment: true, // Create but don't activate until payment
      }),
    })

    const agentData = await agentRes.json() as { success?: boolean; agentId?: string; error?: string }
    if (!agentData.success || !agentData.agentId) {
      setIsDeploying(false)
      alert(`Failed to create agent: ${agentData.error || 'Unknown error'}`)
      return
    }

    const options = {
      key: process.env.NEXT_PUBLIC_RAZORPAY_KEY_ID || 'rzp_test_placeholder',
      amount: plan.inr * 100,
      currency: 'INR',
      name: 'diyaa.ai',
      description: `${agentConfig.agentName} — ${plan.label}`,
      image: '/logo.png',
      notes: {
        agentType: agentName,
        userId: user.id,
        plan: selectedPlan,
        agentId: agentData.agentId, // Add agentId so webhook can activate it
      },
      theme: { color: '#2563EB' },
      handler: async (response: { razorpay_payment_id: string }) => {
        await deployAgent(response.razorpay_payment_id)
      },
      modal: {
        ondismiss: () => setIsDeploying(false),
      },
    }

    try {
      const rzp = new window.Razorpay(options)
      rzp.open()
    } catch {
      // Razorpay not available, deploy directly
      await deployAgent()
    }
  }

  const deployAgent = async (paymentId?: string) => {
    if (!user || !agentConfig) return
    setIsDeploying(true)

    try {
      const res = await fetch('/api/onboard/deploy', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          agentType: agentName,
          agentIcon,
          config: agentConfig,
          userId: user.id,
          plan: 'agent', // Free trial = Agent tier for 7 days
          paymentId,
          isFreeTrialat: true, // Skip payment requirement for free trial
        }),
      })

      const data = await res.json() as { success?: boolean; agentId?: string; agentName?: string; error?: string }

      if (data.success && data.agentId) {
        router.push(
          `/onboard/success?agentId=${data.agentId}&agentName=${encodeURIComponent(data.agentName || 'Agent')}&icon=${encodeURIComponent(agentIcon)}&trial=1`
        )
      } else {
        throw new Error(data.error || 'Deployment failed')
      }
    } catch (err) {
      console.error('Deploy failed:', err)
      alert(`Deploy error: ${String(err)}`)
      setIsDeploying(false)
    }
  }

  const progressPercent = Math.min((questionCount / 6) * 100, 100)
  const isComplete = !!agentConfig

  return (
    <>
      <Script
        src="https://checkout.razorpay.com/v1/checkout.js"
        onLoad={() => setRazorpayLoaded(true)}
      />

      <div className="flex flex-col h-[calc(100vh-120px)] max-w-2xl mx-auto">
        {/* Header */}
        <div className="bg-white rounded-t-xl border border-gray-200 p-4 flex items-center gap-3">
          <div className="text-3xl">{agentIcon}</div>
          <div className="flex-1">
            <h2 className="font-bold text-gray-900">{agentName} Setup</h2>
            <p className="text-xs text-gray-500">
              {isComplete ? 'Configuration complete! Ready to deploy.' : `Customizing for your business`}
            </p>
          </div>
          {/* Progress Bar */}
          <div className="w-24">
            <div className="flex justify-between text-xs text-gray-500 mb-1">
              <span>{isComplete ? 'Done' : `Q${questionCount}/6`}</span>
              <span>{Math.round(progressPercent)}%</span>
            </div>
            <div className="h-1.5 bg-gray-200 rounded-full overflow-hidden">
              <div
                className="h-full bg-blue-600 rounded-full transition-all duration-500"
                style={{ width: `${progressPercent}%` }}
              />
            </div>
          </div>
        </div>

        {/* Chat Area */}
        <div className="flex-1 overflow-y-auto bg-gray-50 border-x border-gray-200 p-4 space-y-4">
          {messages.map((msg, i) => (
            <div
              key={i}
              className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}
            >
              {msg.role === 'assistant' && (
                <div className="w-8 h-8 rounded-full bg-blue-600 flex items-center justify-center text-sm mr-2 flex-shrink-0 mt-1">
                  🤖
                </div>
              )}
              <div
                className={`max-w-[80%] rounded-2xl px-4 py-3 text-sm leading-relaxed ${
                  msg.role === 'user'
                    ? 'bg-blue-600 text-white rounded-br-sm'
                    : 'bg-white text-gray-800 border border-gray-200 rounded-bl-sm shadow-sm'
                }`}
              >
                {msg.content || (
                  <span className="flex gap-1">
                    <span className="w-2 h-2 bg-gray-400 rounded-full animate-bounce" style={{ animationDelay: '0ms' }} />
                    <span className="w-2 h-2 bg-gray-400 rounded-full animate-bounce" style={{ animationDelay: '150ms' }} />
                    <span className="w-2 h-2 bg-gray-400 rounded-full animate-bounce" style={{ animationDelay: '300ms' }} />
                  </span>
                )}
              </div>
              {msg.role === 'user' && (
                <div className="w-8 h-8 rounded-full bg-gray-200 flex items-center justify-center text-sm ml-2 flex-shrink-0 mt-1">
                  👤
                </div>
              )}
            </div>
          ))}

          {/* Config Ready Card */}
          {isComplete && agentConfig && (
            <div className="bg-gradient-to-br from-blue-50 to-indigo-50 border border-blue-200 rounded-xl p-4 mt-4">
              <div className="flex items-center gap-2 mb-3">
                <span className="text-xl">✅</span>
                <h3 className="font-bold text-gray-900">Agent Configured!</h3>
              </div>
              <div className="grid grid-cols-2 gap-2 text-xs mb-4">
                <div className="bg-white rounded-lg p-2 border border-blue-100">
                  <p className="text-gray-500">Business</p>
                  <p className="font-semibold text-gray-800">{agentConfig.businessName}</p>
                </div>
                <div className="bg-white rounded-lg p-2 border border-blue-100">
                  <p className="text-gray-500">Industry</p>
                  <p className="font-semibold text-gray-800">{agentConfig.industry}</p>
                </div>
                <div className="bg-white rounded-lg p-2 border border-blue-100">
                  <p className="text-gray-500">Tone</p>
                  <p className="font-semibold text-gray-800 capitalize">{agentConfig.tone}</p>
                </div>
                <div className="bg-white rounded-lg p-2 border border-blue-100">
                  <p className="text-gray-500">Language</p>
                  <p className="font-semibold text-gray-800">{agentConfig.language}</p>
                </div>
                <div className="bg-white rounded-lg p-2 border border-blue-100 col-span-2">
                  <p className="text-gray-500">Active Hours</p>
                  <p className="font-semibold text-gray-800">{agentConfig.activeHours}</p>
                </div>
              </div>

              {/* Plan Selector */}
              <div className="flex gap-2 mb-3">
                {(['intern', 'agent'] as const).map((plan) => (
                  <div
                    key={plan}
                    className={`flex-1 rounded-lg p-3 border text-center cursor-pointer ${
                      selectedPlan === plan
                        ? 'border-blue-500 bg-blue-50'
                        : 'border-gray-200 bg-white'
                    }`}
                  >
                    <p className="font-bold text-sm text-gray-900 capitalize">{plan}</p>
                    <p className="text-blue-600 font-bold">₹{PLAN_PRICES[plan].inr}/mo</p>
                    <p className="text-xs text-gray-500">${PLAN_PRICES[plan].usd}/mo</p>
                  </div>
                ))}
              </div>

              <div className="space-y-2">
                <button
                  onClick={() => deployAgent()} // Free trial - skip payment
                  disabled={isDeploying}
                  className="w-full bg-green-600 hover:bg-green-700 disabled:bg-green-400 text-white font-bold py-3 rounded-xl text-sm transition-colors flex items-center justify-center gap-2"
                >
                  {isDeploying ? (
                    <>
                      <div className="w-4 h-4 border-2 border-white border-t-transparent rounded-full animate-spin" />
                      Deploying your agent...
                    </>
                  ) : (
                    <>
                      ✨ Start Free Trial (7 days)
                    </>
                  )}
                </button>
                <button
                  onClick={handleQuickDeploy}
                  disabled={isDeploying}
                  className="w-full bg-blue-600 hover:bg-blue-700 disabled:bg-blue-400 text-white font-bold py-3 rounded-xl text-sm transition-colors flex items-center justify-center gap-2"
                >
                  {isDeploying ? '...' : `🚀 Deploy Now — ₹${PLAN_PRICES[selectedPlan].inr}/mo`}
                </button>
              </div>
              <p className="text-xs text-center text-gray-500 mt-2">Choose above: Start free trial OR deploy with payment</p>
            </div>
          )}

          <div ref={messagesEndRef} />
        </div>

        {/* Input Area */}
        <div className="bg-white border border-t-0 border-gray-200 rounded-b-xl p-4">
          {isComplete ? (
            <p className="text-center text-sm text-gray-500">
              Your agent is configured! Click Deploy above to go live. 🎉
            </p>
          ) : (
            <div className="flex gap-2">
              <input
                ref={inputRef}
                type="text"
                value={input}
                onChange={(e) => setInput(e.target.value)}
                onKeyDown={handleKeyDown}
                placeholder="Type your answer..."
                disabled={isStreaming}
                className="flex-1 border border-gray-300 rounded-xl px-4 py-3 text-sm focus:outline-none focus:ring-2 focus:ring-blue-500 disabled:bg-gray-50"
              />
              <button
                onClick={sendMessage}
                disabled={isStreaming || !input.trim()}
                className="bg-blue-600 hover:bg-blue-700 disabled:bg-gray-200 text-white px-5 py-3 rounded-xl font-medium text-sm transition-colors"
              >
                {isStreaming ? '...' : 'Send'}
              </button>
            </div>
          )}
        </div>
      </div>
    </>
  )
}

'use client'

