export async function POST(req: NextRequest) {
  const { agentType, messages } = await req.json() as {
    agentType: string
    messages: Array<{ role: 'user' | 'assistant'; content: string }>
  }

  const apiKey = process.env.GROQ_API_KEY || process.env.GEMINI_API_KEY || ''
  const useGemini = !process.env.GROQ_API_KEY && !!process.env.GEMINI_API_KEY

  const systemPrompt = buildSystemPrompt(agentType)

  // Build messages for AI
  const aiMessages = [
    { role: 'system', content: systemPrompt },
    // Opening message if this is the first exchange
    ...(messages.length === 0
      ? [{
          role: 'assistant' as const,
          content: `Hi! I'm going to ask you a few quick questions to set up your **${agentType}** agent perfectly for your business. It'll only take 2 minutes! 😊\n\nFirst — what's your business name and what do you sell or offer?`
        }]
      : messages
    )
  ]

  // If messages is empty, return opening message instantly (no fake delay)
  if (messages.length === 0) {
    const openingMsg = `Hi! Quick setup for your **${agentType}** agent — just 4 questions 😊\n\nWhat's your business name and what do you sell?`
    const encoder = new TextEncoder()
    const stream = new ReadableStream({
      start(controller) {
        controller.enqueue(encoder.encode(`data: ${JSON.stringify({ token: openingMsg })}\n\n`))
        controller.enqueue(encoder.encode(`data: [DONE]\n\n`))
        controller.close()
      }
    })
    return new Response(stream, {
      headers: { 'Content-Type': 'text/event-stream', 'Cache-Control': 'no-cache', 'Connection': 'keep-alive' }
    })
  }

  // Call AI with streaming
  try {
    let endpoint: string
    let authHeader: string
    let body: Record<string, unknown>

    if (!useGemini) {
      endpoint = 'https://api.groq.com/openai/v1/chat/completions'
      authHeader = `Bearer ${apiKey}`
      body = {
        model: 'llama-3.1-8b-instant',
        messages: aiMessages,
        stream: true,
        temperature: 0.6,
        max_tokens: 180,
      }
    } else {
      endpoint = 'https://generativelanguage.googleapis.com/v1beta/openai/chat/completions'
      authHeader = `Bearer ${apiKey}`
      body = {
        model: 'gemini-2.0-flash',
        messages: aiMessages,
        stream: true,
        temperature: 0.6,
        max_tokens: 180,
      }
    }

    const aiRes = await fetch(endpoint, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        Authorization: authHeader,
      },
      body: JSON.stringify(body),
    })

    if (!aiRes.ok || !aiRes.body) {
      throw new Error(`AI API error: ${aiRes.status}`)
    }

    // Pass through the SSE stream, transforming to our format
    const reader = aiRes.body.getReader()
    const encoder = new TextEncoder()
    const decoder = new TextDecoder()

    const stream = new ReadableStream({
      async start(controller) {
        let buffer = ''
        try {
          while (true) {
            const { done, value } = await reader.read()
            if (done) break

            buffer += decoder.decode(value, { stream: true })
            const lines = buffer.split('\n')
            buffer = lines.pop() || ''

            for (const line of lines) {
              if (!line.startsWith('data: ')) continue
              const data = line.slice(6)
              if (data === '[DONE]') {
                controller.enqueue(encoder.encode('data: [DONE]\n\n'))
                continue
              }
              try {
                const parsed = JSON.parse(data) as {
                  choices?: Array<{ delta?: { content?: string } }>
                }
                const token = parsed.choices?.[0]?.delta?.content
                if (token) {
                  controller.enqueue(encoder.encode(`data: ${JSON.stringify({ token })}\n\n`))
                }
              } catch {
                // skip malformed chunks
              }
            }
          }
        } catch (e) {
          controller.enqueue(encoder.encode(`data: ${JSON.stringify({ error: String(e) })}\n\n`))
        } finally {
          controller.close()
        }
      }
    })

    return new Response(stream, {
      headers: {
        'Content-Type': 'text/event-stream',
        'Cache-Control': 'no-cache',
        'Connection': 'keep-alive',
      }
    })

  } catch (err) {
    return Response.json({ error: String(err) }, { status: 500 })
  }
}

