// ─── Build Tool Definitions from Skill Registry ─────────────────────────────

function buildToolDefs(): ToolDefinition[] {
  return allSkills.map((skill) => ({
    type: 'function' as const,
    function: {
      name: skill.id,
      description: skill.description,
      // Minimal JSON schema representation
      parameters: { type: 'object', properties: {} },
    },
  }))
}

function buildSkillSummaries(): SkillSummary[] {
  return allSkills.map((skill) => ({
    id: skill.id,
    name: skill.name,
    description: skill.description,
  }))
}

// ─── Escalation Detection ────────────────────────────────────────────────────

function needsEscalation(response: string): boolean {
  const escalationPatterns = [
    /speak\s+(?:to|with)\s+(?:a\s+)?(?:human|person|agent|manager|representative)/i,
    /transfer\s+(?:to|me)/i,
    /complaint/i,
    /escalat/i,
    /legal\s+action/i,
    /sue\s+you/i,
    /refund/i,
    /cancel\s+(?:my\s+)?(?:account|subscription|order)/i,
  ]

  return escalationPatterns.some((p) => p.test(response))
}

// ─── Core Execution Loop ────────────────────────────────────────────────────

export async function executeAgent(trigger: ExecutionTrigger): Promise<ExecutionResult> {
  const startTime = Date.now()
  const logs: ExecutionLog[] = []
  let iterationCount = 0
  let toolCallsCount = 0
  let totalCostINR = 0
  let lastProvider = ''
  let lastModel = ''
  let escalation = false

  const log = (
    type: ExecutionLog['type'],
    message: string,
    data?: Record<string, unknown>
  ): void => {
    logs.push({ timestamp: new Date().toISOString(), type, message, data })
  }

  try {
    // ─── Node 1: Load Context ──────────────────────────────────────────
    log('info', `Starting execution for agent ${trigger.agentId}`)

    const agentConfig = await loadAgentConfig(trigger.agentId, trigger.userId)
    log('info', `Loaded agent config: ${agentConfig.name}`)

    const ragContext = await loadRAGContext(trigger.agentId, trigger.message)
    if (ragContext) {
      log('info', `Loaded RAG context (${ragContext.length} chars)`)
    }

    const conversationHistory = await loadConversationHistory(trigger.conversationId)
    log('info', `Loaded ${conversationHistory.length} conversation history messages`)

    // Save the incoming user message (when Supabase is configured)
    await saveMessage(trigger.conversationId, 'user', trigger.message, trigger.agentId)

    // ─── Build System Prompt ───────────────────────────────────────────
    const systemPrompt = buildSystemPrompt({
      agentConfig,
      ragContext: ragContext || undefined,
      conversationHistory,
      currentChannel: trigger.channel,
      customerName: trigger.senderName,
      customerInfo: trigger.senderInfo,
      currentTime: new Date().toLocaleString('en-IN', { timeZone: 'Asia/Kolkata' }),
      availableSkills: buildSkillSummaries(),
    })

    const toolDefs = buildToolDefs()

    // ─── Build Message Array ───────────────────────────────────────────
    const messages: AIMessage[] = [
      { role: 'system', content: systemPrompt },
      ...formatConversationHistory(conversationHistory).map((m) => ({
        role: m.role as 'user' | 'assistant',
        content: m.content,
      })),
      { role: 'user' as const, content: trigger.message },
    ]

    // ─── Safety Config ─────────────────────────────────────────────────
    const safetyConfig: SafetyConfig = {
      ...DEFAULT_SAFETY_CONFIG,
      activeHoursStart: agentConfig.activeHours.start,
      activeHoursEnd: agentConfig.activeHours.end,
    }

    // ─── Node 2-3: LLM Decision Loop ──────────────────────────────────
    while (iterationCount < safetyConfig.maxIterations) {
      // ─── Node 5: Safety Check (every iteration) ─────────────────────
      const safetyState: SafetyState = {
        agentId: trigger.agentId,
        userId: trigger.userId,
        iterationCount,
        runCostINR: totalCostINR,
        actionsThisHour: 0, // Tracked internally by safety module
        actionsToday: 0,
        dailyCostINR: 0,
      }

      const safetyResult = runSafetyChecks(safetyState, safetyConfig)

      if (!safetyResult.allowed) {
        log('safety', `Safety check blocked: ${safetyResult.reason}`)
        return {
          success: false,
          response: 'I apologize, but I am unable to continue processing at this time. A team member will follow up with you shortly.',
          toolCallsCount,
          iterationCount,
          totalCostINR,
          provider: lastProvider,
          model: lastModel,
          logs,
          durationMs: Date.now() - startTime,
          needsEscalation: true,
          error: safetyResult.reason,
        }
      }

      if (safetyResult.level === 'warn') {
        log('safety', `Safety warning: ${safetyResult.reason}`)
      }

      // ─── Node 2: LLM Decision ──────────────────────────────────────
      iterationCount++
      log('info', `Iteration ${iterationCount}: calling LLM`)

      const aiResponse = await callAI({
        messages,
        tools: toolDefs,
        temperature: 0.7,
        maxTokens: 2048,
      })

      lastProvider = aiResponse.provider
      lastModel = aiResponse.model

      const iterCost = estimateCostINR(aiResponse.provider, aiResponse.usage)
      totalCostINR += iterCost
      recordCost(trigger.agentId, iterCost)

      log('info', `LLM response from ${aiResponse.provider}/${aiResponse.model} (cost: ₹${iterCost.toFixed(2)})`, {
        usage: aiResponse.usage as unknown as Record<string, unknown>,
      })

      // ─── Handle Tool Calls ──────────────────────────────────────────
      if (aiResponse.tool_calls.length > 0) {
        // Add assistant message with tool calls
        messages.push({
          role: 'assistant',
          content: aiResponse.content ?? '',
          tool_calls: aiResponse.tool_calls,
        })

        for (const toolCall of aiResponse.tool_calls) {
          toolCallsCount++
          recordAction(trigger.agentId)

          log('tool_call', `Calling tool: ${toolCall.function.name}`, {
            arguments: safeParseJSON(toolCall.function.arguments),
          })

          const skillResult = await executeToolCall(toolCall, {
            agentId: trigger.agentId,
            userId: trigger.userId,
            businessName: agentConfig.businessName,
            channel: trigger.channel,
            conversationId: trigger.conversationId,
          })

          log('tool_result', `Tool ${toolCall.function.name}: ${skillResult.success ? 'success' : 'failed'}`, {
            output: skillResult.output,
            error: skillResult.error,
          })

          // Feed tool result back to the conversation
          messages.push({
            role: 'tool',
            content: skillResult.success
              ? skillResult.output
              : `Error: ${skillResult.error ?? 'Unknown error'}`,
            tool_call_id: toolCall.id,
          })
        }

        // Loop back to Node 2 for next LLM decision
        continue
      }

      // ─── Node 4: Text Output ───────────────────────────────────────
      const responseText = aiResponse.content ?? 'I apologize, but I was unable to generate a response.'

      log('llm_response', `Final response generated (${responseText.length} chars)`)

      // Check for escalation signals
      escalation = needsEscalation(trigger.message) || needsEscalation(responseText)
      if (escalation) {
        log('info', 'Escalation detected — flagging for human review')
      }

      // Send via the appropriate channel
      await sendViaChannel(trigger.channel, trigger.agentId, '', responseText)
      log('output', `Response sent via ${trigger.channel}`)

      // Save assistant response (when Supabase is configured)
      await saveMessage(trigger.conversationId, 'assistant', responseText, trigger.agentId)

      return {
        success: true,
        response: responseText,
        toolCallsCount,
        iterationCount,
        totalCostINR,
        provider: lastProvider,
        model: lastModel,
        logs,
        durationMs: Date.now() - startTime,
        needsEscalation: escalation,
      }
    }

    // If we exhausted all iterations
    log('safety', `Max iterations (${safetyConfig.maxIterations}) reached`)
    const fallbackResponse = 'I have been working on your request but need more time. Let me connect you with a team member who can help further.'

    await sendViaChannel(trigger.channel, trigger.agentId, '', fallbackResponse)
    await saveMessage(trigger.conversationId, 'assistant', fallbackResponse, trigger.agentId)

    return {
      success: true,
      response: fallbackResponse,
      toolCallsCount,
      iterationCount,
      totalCostINR,
      provider: lastProvider,
      model: lastModel,
      logs,
      durationMs: Date.now() - startTime,
      needsEscalation: true,
    }
  } catch (e: unknown) {
    const errorMsg = e instanceof Error ? e.message : String(e)
    log('error', `Execution failed: ${errorMsg}`)

    return {
      success: false,
      response: 'I apologize, but I encountered an issue processing your request. Please try again or contact support.',
      toolCallsCount,
      iterationCount,
      totalCostINR,
      provider: lastProvider,
      model: lastModel,
      logs,
      durationMs: Date.now() - startTime,
      needsEscalation: true,
      error: errorMsg,
    }
  }
}

// ─── Helpers ─────────────────────────────────────────────────────────────────

async function executeToolCall(
  toolCall: ToolCall,
  context: AgentContext
): Promise<{ success: boolean; output: string; error?: string }> {
  try {
    const args = safeParseJSON(toolCall.function.arguments)
    const result = await executeSkill(toolCall.function.name, args, context)
    return { success: result.success, output: result.output, error: result.error }
  } catch (e: unknown) {
    const msg = e instanceof Error ? e.message : String(e)
    return { success: false, output: '', error: msg }
  }
}

function safeParseJSON(str: string): Record<string, unknown> {
  try {
    return JSON.parse(str) as Record<string, unknown>
  } catch {
    return { raw: str }
  }
}

/**
 * Shared Agent Executor — same pattern for all 20 agents
 * RAG + LLM + Action routing
 */

import { createClient } from '@supabase/supabase-js'
import { getAgentPrompt, AgentType, AgentPromptConfig } from './all-prompts'

const supabaseAdmin = createClient(
  process.env.NEXT_PUBLIC_SUPABASE_URL!,
  process.env.SUPABASE_SERVICE_ROLE_KEY!
)

export interface ExecuteInput {
  agentId: string
  agentType: AgentType
  message: string
  channel: 'whatsapp' | 'email' | 'api' | 'widget'
  fromPhone?: string
  fromEmail?: string
  conversationId?: string
  metadata?: Record<string, unknown>
}

export interface ExecuteResult {
  success: boolean
  response: string
  parsedData?: Record<string, unknown>
  action?: string
  conversationId?: string
  error?: string
}

export async function executeAgent(input: ExecuteInput): Promise<ExecuteResult> {
  try {
    // 1. Load agent from DB
    const { data: agent, error: agentError } = await supabaseAdmin
      .from('agents')
      .select('*')
      .eq('id', input.agentId)
      .single()

    if (agentError || !agent) {
      return { success: false, response: '', error: 'Agent not found' }
    }

    // 2. Get or create conversation
    let conversationId = input.conversationId
    if (!conversationId) {
      const identifier = input.fromPhone || input.fromEmail || 'anonymous'
      const { data: existingConv } = await supabaseAdmin
        .from('conversations')
        .select('id')
        .eq('agent_id', input.agentId)
        .eq('customer_identifier', identifier)
        .order('created_at', { ascending: false })
        .limit(1)
        .single()

      if (existingConv) {
        conversationId = existingConv.id
      } else {
        const { data: newConv } = await supabaseAdmin
          .from('conversations')
          .insert({
            agent_id: input.agentId,
            user_id: agent.user_id,
            customer_identifier: identifier,
            channel: input.channel,
            status: 'active',
          })
          .select('id')
          .single()
        conversationId = newConv?.id
      }
    }

    // 3. Store incoming message
    if (conversationId) {
      await supabaseAdmin.from('messages').insert({
        conversation_id: conversationId,
        agent_id: input.agentId,
        role: 'user',
        content: input.message,
        channel: input.channel,
      })
    }

    // 4. Load conversation history (last 10 messages)
    let history: Array<{ role: string; content: string }> = []
    if (conversationId) {
      const { data: msgs } = await supabaseAdmin
        .from('messages')
        .select('role, content')
        .eq('conversation_id', conversationId)
        .order('created_at', { ascending: false })
        .limit(10)
      history = (msgs || []).reverse()
    }

    // 5. Load knowledge base (RAG context)
    let ragContext = ''
    const { data: knowledgeDocs } = await supabaseAdmin
      .from('knowledge_documents')
      .select('content')
      .eq('agent_id', input.agentId)
      .limit(5)
    if (knowledgeDocs && knowledgeDocs.length > 0) {
      ragContext = knowledgeDocs.map((d: { content: string }) => d.content).join('\n\n')
    }

    // 6. Build system prompt
    const promptConfig: AgentPromptConfig = {
      businessName: agent.business_name || agent.name,
      businessKnowledge: ragContext || agent.business_description || 'No specific knowledge uploaded yet.',
      tone: agent.tone || 'professional',
      language: 'English (auto-detect Hinglish)',
      activeHours: `${agent.active_hours_start || 9}am-${agent.active_hours_end || 21}pm IST`,
      agentName: agent.name,
    }

    const systemPrompt = getAgentPrompt(input.agentType, promptConfig)

    // 7. Call LLM via router
    const { callAI } = await import('@/lib/ai/router')
    const messages = [
      { role: 'system' as const, content: systemPrompt },
      ...history.map((m) => ({ role: m.role as 'user' | 'assistant', content: m.content })),
      { role: 'user' as const, content: input.message },
    ]

    const aiResult = await callAI({
      messages,
      temperature: 0.7,
      maxTokens: 800,
    })
    const llmResponse = aiResult.content || "I couldn't generate a response right now."

    // 8. Parse JSON response from LLM
    let parsedData: Record<string, unknown> = {}
    let responseMessage = llmResponse

    try {
      const jsonMatch = llmResponse.match(/\{[\s\S]*\}/)
      if (jsonMatch) {
        parsedData = JSON.parse(jsonMatch[0])
        responseMessage = (parsedData.message as string) || llmResponse
      }
    } catch {
      // LLM returned plain text, use as-is
      responseMessage = llmResponse
    }

    // 9. Store agent response
    if (conversationId) {
      await supabaseAdmin.from('messages').insert({
        conversation_id: conversationId,
        agent_id: input.agentId,
        role: 'agent',
        content: responseMessage,
        channel: input.channel,
      })
    }

    // 10. Log execution
    await supabaseAdmin.from('agent_executions').insert({
      agent_id: input.agentId,
      agent_type: input.agentType,
      input: { message: input.message, channel: input.channel },
      output: { message: responseMessage, data: parsedData },
      conversation_id: conversationId,
    })

    return {
      success: true,
      response: responseMessage,
      parsedData,
      action: parsedData.action as string || parsedData.nextAction as string,
      conversationId,
    }
  } catch (error) {
    console.error('Agent execution error:', error)
    return {
      success: false,
      response: "I'm having a moment. Please try again shortly.",
      error: error instanceof Error ? error.message : 'Unknown error',
    }
  }
}

/**
 * System Prompt Builder — constructs context-rich prompts for agents
 * Takes agent config + RAG context + conversation history → system prompt
 */

export interface AgentConfig {
  id: string
  userId: string
  name: string
  businessName: string
  industry: string
  products: string[]
  knowledgeBase: string
  tone: string
  activeHours: { start: number; end: number }
  channels: string[]
  modelTier: 'free' | 'pro' | 'enterprise'
  systemPromptOverride?: string
  language?: string
  maxResponseLength?: number
}

export interface PromptContext {
  agentConfig: AgentConfig
  ragContext?: string
  conversationHistory?: ConversationMessage[]
  currentChannel: string
  customerName?: string
  customerInfo?: string
  currentTime: string
  availableSkills: SkillSummary[]
}

export interface ConversationMessage {
  role: 'user' | 'assistant'
  content: string
  timestamp: string
}

export interface SkillSummary {
  id: string
  name: string
  description: string
}

/**
 * Builds the complete system prompt for an agent execution run.
 */
export function buildSystemPrompt(ctx: PromptContext): string {
  const { agentConfig, ragContext, currentChannel, customerName, availableSkills } = ctx

  // If the user has a custom system prompt override, prepend it
  const customSection = agentConfig.systemPromptOverride
    ? `\n## Custom Instructions\n${agentConfig.systemPromptOverride}\n`
    : ''

  const skillList = availableSkills
    .map((s) => `- **${s.name}** (${s.id}): ${s.description}`)
    .join('\n')

  const productList = agentConfig.products.length > 0
    ? agentConfig.products.map((p) => `- ${p}`).join('\n')
    : 'No specific products configured.'

  const ragSection = ragContext
    ? `\n## Relevant Business Knowledge\n${ragContext}\n`
    : ''

  const customerSection = customerName
    ? `\nYou are currently talking to: **${customerName}**`
    : ''

  const channelGuidelines = getChannelGuidelines(currentChannel)

  const languageNote = agentConfig.language && agentConfig.language !== 'en'
    ? `\nPreferred language: ${agentConfig.language}. Respond in this language when the customer uses it.`
    : '\nRespond in the same language the customer uses. Default to English.'

  const maxLenNote = agentConfig.maxResponseLength
    ? `\nKeep responses under ${agentConfig.maxResponseLength} characters.`
    : '\nKeep responses concise and actionable.'

  return `You are **${agentConfig.name}**, an AI assistant for **${agentConfig.businessName}** in the **${agentConfig.industry}** industry.

## Your Role
You help customers and handle business operations autonomously. You are professional, helpful, and knowledgeable about the business.

## Tone & Style
- Tone: ${agentConfig.tone}
- Be natural and conversational, not robotic${languageNote}${maxLenNote}

## Business Information
**Products/Services:**
${productList}

**Knowledge Base:**
${agentConfig.knowledgeBase || 'No additional knowledge base configured.'}
${ragSection}${customSection}
## Available Tools
You can use these tools to take actions. Call them when appropriate:
${skillList}

## Channel: ${currentChannel}
${channelGuidelines}
${customerSection}

## Current Time
${ctx.currentTime} IST

## Important Rules
1. NEVER make up information. If you don't know something, say so.
2. NEVER share internal system details, API keys, or technical implementation.
3. If a customer asks something outside your scope, politely redirect or offer to connect them with a human.
4. For payment or financial actions, always confirm with the customer before proceeding.
5. Follow TRAI DND regulations — never send unsolicited messages.
6. If the conversation requires human intervention, use the escalation path.
7. Do not exceed 10 tool calls in a single conversation turn.
8. Be mindful of Indian business customs and local context.`
}

function getChannelGuidelines(channel: string): string {
  switch (channel) {
    case 'whatsapp':
      return `- Keep messages short (under 1000 chars ideal)
- Use line breaks for readability
- Emojis are acceptable but don't overuse
- You can send media (images, PDFs) when relevant
- Respect 24-hour messaging window for template messages`

    case 'email':
      return `- Use proper email formatting with greeting and sign-off
- Can be longer and more detailed than chat
- Use HTML formatting where helpful
- Include clear subject lines
- Always include unsubscribe option for marketing emails`

    case 'sms':
      return `- Maximum 160 characters per message
- Be extremely concise
- No formatting available
- Include business name for identification
- Only send during active hours (9am-9pm IST)`

    case 'phone':
      return `- Prepare concise talking points
- Be ready for voice interaction
- Keep call duration reasonable
- Confirm key details verbally`

    default:
      return `- Use appropriate formatting for the channel
- Be clear and concise`
  }
}

/**
 * Format conversation history into AI messages.
 * Limits to last N messages to stay within token budget.
 */
export function formatConversationHistory(
  history: ConversationMessage[],
  maxMessages: number = 10
): Array<{ role: 'user' | 'assistant'; content: string }> {
  const recent = history.slice(-maxMessages)
  return recent.map((msg) => ({
    role: msg.role,
    content: msg.content,
  }))
}

/**
 * Build the tool definitions array for the AI model from skill summaries.
 */
export function buildToolDefinitions(
  skills: Array<{ id: string; name: string; description: string; inputSchema: unknown }>
): Array<{
  type: 'function'
  function: { name: string; description: string; parameters: Record<string, unknown> }
}> {
  return skills.map((skill) => ({
    type: 'function' as const,
    function: {
      name: skill.id,
      description: skill.description,
      parameters: (skill.inputSchema && typeof skill.inputSchema === 'object' && 'shape' in (skill.inputSchema as Record<string, unknown>))
        ? zodToJsonSchema(skill.inputSchema)
        : (skill.inputSchema as Record<string, unknown>) ?? { type: 'object', properties: {} },
    },
  }))
}

/**
 * Minimal Zod-to-JSON-Schema converter for tool definitions.
 * Handles the common cases used in our skill registry.
 */
function zodToJsonSchema(schema: unknown): Record<string, unknown> {
  // For actual production use, consider the zod-to-json-schema package.
  // This is a minimal fallback that wraps the schema description.
  if (schema && typeof schema === 'object' && '_def' in (schema as Record<string, unknown>)) {
    const def = (schema as Record<string, unknown>)._def as Record<string, unknown>
    if (def.typeName === 'ZodObject' && def.shape) {
      const shape = typeof def.shape === 'function' ? (def.shape as () => Record<string, unknown>)() : def.shape as Record<string, unknown>
      const properties: Record<string, unknown> = {}
      const required: string[] = []

      for (const [key, value] of Object.entries(shape)) {
        const fieldDef = (value as Record<string, unknown>)?._def as Record<string, unknown> | undefined
        if (fieldDef) {
          const isOptional = fieldDef.typeName === 'ZodOptional'
          if (!isOptional) {
            required.push(key)
          }
          properties[key] = { type: 'string', description: (fieldDef.description as string) ?? '' }
        }
      }

      return { type: 'object', properties, required }
    }
  }

  return { type: 'object', properties: {} }
}

/**
 * AI Model Router — cascading fallback chain
 * Groq (fastest, free tier) → Gemini (Google) → Kimi (Moonshot backup)
 * Each provider gets one attempt before falling through.
 */

export interface ModelProvider {
  provider: 'groq' | 'gemini' | 'kimi'
  model: string
  endpoint: string
  apiKeyEnv: string
}

export interface AIMessage {
  role: 'system' | 'user' | 'assistant' | 'tool'
  content: string
  tool_call_id?: string
  tool_calls?: ToolCall[]
}

export interface ToolCall {
  id: string
  type: 'function'
  function: {
    name: string
    arguments: string
  }
}

export interface ToolDefinition {
  type: 'function'
  function: {
    name: string
    description: string
    parameters: Record<string, unknown>
  }
}

export interface AIResponse {
  content: string | null
  tool_calls: ToolCall[]
  provider: string
  model: string
  usage: { prompt_tokens: number; completion_tokens: number; total_tokens: number }
}

const modelFallbackChain: ModelProvider[] = [
  {
    provider: 'groq',
    model: 'llama-3.3-70b-versatile',
    endpoint: 'https://api.groq.com/openai/v1/chat/completions',
    apiKeyEnv: 'GROQ_API_KEY',
  },
  {
    provider: 'gemini',
    model: 'gemini-2.0-flash',
    endpoint: 'https://generativelanguage.googleapis.com/v1beta/openai/chat/completions',
    apiKeyEnv: 'GOOGLE_GENERATIVE_AI_API_KEY',
  },
  {
    provider: 'kimi',
    model: 'kimi-k2.5',
    endpoint: 'https://api.moonshot.cn/v1/chat/completions',
    apiKeyEnv: 'KIMI_API_KEY',
  },
]

interface CallAIOptions {
  messages: AIMessage[]
  tools?: ToolDefinition[]
  temperature?: number
  maxTokens?: number
  /** Override the default fallback chain with a specific provider */
  forceProvider?: 'groq' | 'gemini' | 'kimi'
}

async function callProvider(
  provider: ModelProvider,
  options: CallAIOptions
): Promise<AIResponse> {
  const apiKey = process.env[provider.apiKeyEnv] || ''

  if (!apiKey) {
    throw new Error(`Missing API key for ${provider.provider} (env: ${provider.apiKeyEnv})`)
  }

  const body: Record<string, unknown> = {
    model: provider.model,
    messages: options.messages,
    temperature: options.temperature ?? 0.7,
    max_tokens: options.maxTokens ?? 2048,
  }

  if (options.tools && options.tools.length > 0) {
    body.tools = options.tools
    body.tool_choice = 'auto'
  }

  const res = await fetch(provider.endpoint, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      Authorization: `Bearer ${apiKey}`,
    },
    body: JSON.stringify(body),
    signal: AbortSignal.timeout(30_000),
  })

  if (!res.ok) {
    const errorText = await res.text().catch(() => 'Unknown error')
    throw new Error(`${provider.provider} API error ${res.status}: ${errorText}`)
  }

  const data = await res.json() as {
    choices: Array<{
      message: {
        content: string | null
        tool_calls?: ToolCall[]
      }
    }>
    usage?: { prompt_tokens?: number; completion_tokens?: number; total_tokens?: number }
  }

  const choice = data.choices?.[0]
  if (!choice) {
    throw new Error(`${provider.provider} returned empty response`)
  }

  return {
    content: choice.message.content,
    tool_calls: choice.message.tool_calls ?? [],
    provider: provider.provider,
    model: provider.model,
    usage: {
      prompt_tokens: data.usage?.prompt_tokens ?? 0,
      completion_tokens: data.usage?.completion_tokens ?? 0,
      total_tokens: data.usage?.total_tokens ?? 0,
    },
  }
}

/**
 * Call AI with automatic fallback across providers.
 * Tries Groq → Gemini → Kimi. If all fail, throws the last error.
 */
export async function callAI(options: CallAIOptions): Promise<AIResponse> {
  // If a specific provider is forced, only try that one
  if (options.forceProvider) {
    const provider = modelFallbackChain.find((p) => p.provider === options.forceProvider)
    if (!provider) {
      throw new Error(`Unknown provider: ${options.forceProvider}`)
    }
    return callProvider(provider, options)
  }

  const errors: string[] = []

  for (const provider of modelFallbackChain) {
    try {
      return await callProvider(provider, options)
    } catch (e: unknown) {
      const msg = e instanceof Error ? e.message : String(e)
      errors.push(`[${provider.provider}] ${msg}`)
      // Continue to next provider
    }
  }

  throw new Error(`All AI providers failed:\n${errors.join('\n')}`)
}

/**
 * Estimate cost for a given usage in INR.
 * Rough per-1K-token rates for budgeting / safety checks.
 */
export function estimateCostINR(
  provider: string,
  usage: { prompt_tokens: number; completion_tokens: number }
): number {
  // Approximate rates in INR per 1K tokens (input + output blended)
  const rates: Record<string, { input: number; output: number }> = {
    groq: { input: 0.05, output: 0.08 },    // Near-free tier
    gemini: { input: 0.03, output: 0.06 },   // Google free tier generous
    kimi: { input: 0.10, output: 0.15 },      // Moonshot pricing
  }

  const rate = rates[provider] ?? { input: 0.10, output: 0.15 }
  const inputCost = (usage.prompt_tokens / 1000) * rate.input
  const outputCost = (usage.completion_tokens / 1000) * rate.output

  return Math.round((inputCost + outputCost) * 100) / 100
}

/**
 * TRAI DND Compliance — Consent Layer
 * Every outbound action checks consent before executing.
 * violating = ₹1,500 fine per message under TRAI regulations
 */

export type ConsentType = 'whatsapp' | 'sms' | 'call' | 'email'

export interface Contact {
  id: string
  phone?: string
  email?: string
  whatsapp_consent: boolean
  sms_consent: boolean
  call_consent: boolean
  email_consent: boolean
  consent_date?: string
  consent_source?: 'form' | 'inbound' | 'manual'
}

export class ConsentError extends Error {
  constructor(public channel: ConsentType, public contactId: string) {
    super(`DND_BLOCKED: Contact ${contactId} has not consented to ${channel} messages`)
    this.name = 'ConsentError'
  }
}

export function checkConsent(contact: Contact, channel: ConsentType): void {
  const consentMap: Record<ConsentType, boolean> = {
    whatsapp: contact.whatsapp_consent,
    sms: contact.sms_consent,
    call: contact.call_consent,
    email: contact.email_consent,
  }

  if (!consentMap[channel]) {
    throw new ConsentError(channel, contact.id)
  }
}

export function isInboundConsent(source: Contact['consent_source']): boolean {
  // Inbound contacts = implicit consent (they initiated contact)
  return source === 'inbound'
}

