/**
 * Generate secure webhook token (for webhook verification)
 */
export function generateWebhookToken(): string {
  return crypto.randomBytes(32).toString('hex')
}

/**
 * Verify webhook signature (HMAC-SHA256)
 */
export function verifyWebhookSignature(payload: string, signature: string, token: string): boolean {
  const computed = crypto.createHmac('sha256', token).update(payload).digest('hex')
  return crypto.timingSafeEqual(Buffer.from(computed), Buffer.from(signature))
}

