import type { AgentJobData } from '@/lib/queue/worker'
import { activateKillSwitch } from '@/lib/agent/safety'

// ─── Redis Connection ────────────────────────────────────────────────────────

function getRedisConnection(): any {
  const redisUrl = process.env.REDIS_URL

  if (redisUrl) {
    // Use the Redis URL directly (e.g., from Railway or Upstash)
    return redisUrl
  }

  // Fallback to individual env vars
  return {
    host: process.env.REDIS_HOST || 'localhost',
    port: parseInt(process.env.REDIS_PORT || '6379', 10),
    password: process.env.REDIS_PASSWORD || undefined,
    maxRetriesPerRequest: null,
  }
}

// ─── Queue Singleton ─────────────────────────────────────────────────────────

// eslint-disable-next-line @typescript-eslint/no-explicit-any
let queueInstance: any = null
let queueEventsInstance: QueueEvents | null = null

function getQueue(): Queue<AgentJobData> {
  if (!queueInstance) {
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    queueInstance = new Queue<AgentJobData>(AGENT_QUEUE_NAME, {
      connection: getRedisConnection() as any,
      defaultJobOptions: {
        attempts: 3,
        backoff: {
          type: 'exponential',
          delay: 5000,
        },
        removeOnComplete: {
          age: 86_400,
          count: 1000,
        },
        removeOnFail: {
          age: 604_800,
        },
      },
    })
  }
  return queueInstance!
}

function getQueueEvents(): QueueEvents {
  if (!queueEventsInstance) {
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    queueEventsInstance = new QueueEvents(AGENT_QUEUE_NAME, {
      connection: getRedisConnection() as any,
    })
  }
  return queueEventsInstance!
}

// ─── Queue a One-Time Agent Job ──────────────────────────────────────────────

export interface QueueJobOptions {
  priority?: number
  delay?: number
  jobId?: string
}

export async function queueAgentJob(
  trigger: ExecutionTrigger,
  options: QueueJobOptions = {}
): Promise<{ jobId: string }> {
  const queue = getQueue()

  const job = await queue.add(
    `agent-${trigger.agentId}`,
    { trigger, priority: options.priority },
    {
      priority: options.priority ?? 0,
      delay: options.delay,
      jobId: options.jobId,
    }
  )

  console.log(`[Producer] Queued job ${job.id} for agent ${trigger.agentId}`)

  return { jobId: job.id ?? `unknown-${Date.now()}` }
}

// ─── Schedule a Recurring Agent Job ──────────────────────────────────────────

export interface ScheduleJobOptions {
  cronExpression: string
  trigger: ExecutionTrigger
  jobId?: string
  timezone?: string
}

export async function scheduleAgentJob(
  options: ScheduleJobOptions
): Promise<{ jobId: string }> {
  const queue = getQueue()

  const jobId = options.jobId ?? `scheduled-${options.trigger.agentId}-${Date.now()}`

  await queue.add(
    `scheduled-${options.trigger.agentId}`,
    { trigger: options.trigger },
    {
      repeat: {
        pattern: options.cronExpression,
        tz: options.timezone ?? 'Asia/Kolkata',
      },
      jobId,
    }
  )

  console.log(
    `[Producer] Scheduled recurring job ${jobId} for agent ${options.trigger.agentId} ` +
    `with cron: ${options.cronExpression}`
  )

  return { jobId }
}

// ─── Pause All Agents for a User ─────────────────────────────────────────────

export async function pauseAllAgents(userId: string): Promise<{ removedCount: number }> {
  const queue = getQueue()

  // Activate the kill switch so running agents stop at next safety check
  activateKillSwitch(userId)

  // Remove all waiting jobs that belong to this user
  const waitingJobs = await queue.getWaiting(0, 1000)
  const delayedJobs = await queue.getDelayed(0, 1000)

  const allJobs = [...waitingJobs, ...delayedJobs]
  let removedCount = 0

  for (const job of allJobs) {
    if (job.data.trigger.userId === userId) {
      await job.remove()
      removedCount++
    }
  }

  // Remove repeatable jobs for this user
  const repeatableJobs = await queue.getRepeatableJobs()
  for (const rJob of repeatableJobs) {
    // Repeatable job names contain the agent ID; check if they belong to this user
    // In production, store userId mapping. For now, remove by name pattern.
    if (rJob.name.includes(userId)) {
      await queue.removeRepeatableByKey(rJob.key)
      removedCount++
    }
  }

  console.log(`[Producer] Paused all agents for user ${userId}. Removed ${removedCount} jobs.`)

  return { removedCount }
}

// ─── Job Status ──────────────────────────────────────────────────────────────

export interface JobStatus {
  id: string
  state: string
  progress: unknown
  data: AgentJobData
  failedReason?: string
  finishedOn?: number
  processedOn?: number
}

export async function getJobStatus(jobId: string): Promise<JobStatus | null> {
  const queue = getQueue()
  const job = await queue.getJob(jobId)

  if (!job) return null

  const state = await job.getState()

  return {
    id: job.id ?? jobId,
    state,
    progress: job.progress,
    data: job.data,
    failedReason: job.failedReason,
    finishedOn: job.finishedOn,
    processedOn: job.processedOn,
  }
}

// ─── Wait for Job Completion ─────────────────────────────────────────────────

export async function waitForJob(
  jobId: string,
  timeoutMs: number = 60_000
): Promise<unknown> {
  const queue = getQueue()
  const job = await queue.getJob(jobId)

  if (!job) {
    throw new Error(`Job ${jobId} not found`)
  }

  const events = getQueueEvents()
  await events.waitUntilReady()

  return await job.waitUntilFinished(events, timeoutMs)
}

// ─── Cleanup ─────────────────────────────────────────────────────────────────

export async function closeQueue(): Promise<void> {
  if (queueInstance) {
    await queueInstance.close()
    queueInstance = null
  }
  if (queueEventsInstance) {
    await queueEventsInstance.close()
    queueEventsInstance = null
  }
}

/**
 * BullMQ Worker — processes agent execution jobs from Redis queue
 *
 * Connects to Redis, listens for 'agent-execution' jobs,
 * runs the executor, and handles failures gracefully.
 */

import { Worker, Job } from 'bullmq'
import { executeAgent } from '@/lib/agent/executor'
import type { ExecutionTrigger, ExecutionResult } from '@/lib/agent/executor'

// ─── Types ───────────────────────────────────────────────────────────────────

export interface AgentJobData {
  trigger: ExecutionTrigger
  priority?: number
  retryCount?: number
}

export interface AgentJobResult {
  executionResult: ExecutionResult
  completedAt: string
}

// ─── Redis Connection Config ─────────────────────────────────────────────────

function getRedisConnection() {
  return {
    host: process.env.REDIS_HOST || 'localhost',
    port: parseInt(process.env.REDIS_PORT || '6379', 10),
    password: process.env.REDIS_PASSWORD || undefined,
    maxRetriesPerRequest: null as null,
  }
}

// ─── Queue Name ──────────────────────────────────────────────────────────────

export const AGENT_QUEUE_NAME = 'agent-execution'

// ─── Job Processor ───────────────────────────────────────────────────────────

async function processAgentJob(job: Job<AgentJobData>): Promise<AgentJobResult> {
  const { trigger } = job.data

  console.log(
    `[Worker] Processing job ${job.id} — agent: ${trigger.agentId}, channel: ${trigger.channel}`
  )

  await job.updateProgress(10)

  try {
    const executionResult = await executeAgent(trigger)

    await job.updateProgress(100)

    console.log(
      `[Worker] Job ${job.id} completed — success: ${executionResult.success}, ` +
      `iterations: ${executionResult.iterationCount}, tools: ${executionResult.toolCallsCount}, ` +
      `cost: ₹${executionResult.totalCostINR.toFixed(2)}, duration: ${executionResult.durationMs}ms`
    )

    if (executionResult.needsEscalation) {
      console.log(`[Worker] Job ${job.id} flagged for escalation`)
      // TODO: Push to inbox / notify human agent
    }

    if (!executionResult.success) {
      console.error(`[Worker] Job ${job.id} execution failed: ${executionResult.error}`)
    }

    return {
      executionResult,
      completedAt: new Date().toISOString(),
    }
  } catch (e: unknown) {
    const errorMsg = e instanceof Error ? e.message : String(e)
    console.error(`[Worker] Job ${job.id} threw error: ${errorMsg}`)
    throw e // Let BullMQ handle retry
  }
}

// ─── Create Worker ───────────────────────────────────────────────────────────

let workerInstance: Worker<AgentJobData, AgentJobResult> | null = null

export function createAgentWorker(): Worker<AgentJobData, AgentJobResult> {
  if (workerInstance) {
    return workerInstance
  }

  const worker = new Worker<AgentJobData, AgentJobResult>(
    AGENT_QUEUE_NAME,
    processAgentJob,
    {
      connection: getRedisConnection(),
      concurrency: parseInt(process.env.WORKER_CONCURRENCY || '5', 10),
      limiter: {
        max: 100,
        duration: 60_000, // 100 jobs per minute max
      },
      removeOnComplete: {
        age: 86_400, // Keep completed jobs for 24 hours
        count: 1000,  // Keep last 1000 completed jobs
      },
      removeOnFail: {
        age: 604_800, // Keep failed jobs for 7 days
      },
    }
  )

  // ─── Event Handlers ──────────────────────────────────────────────────

  worker.on('completed', (job: Job<AgentJobData, AgentJobResult>) => {
    console.log(`[Worker] Job ${job.id} completed successfully`)
  })

  worker.on('failed', (job: Job<AgentJobData, AgentJobResult> | undefined, err: Error) => {
    console.error(`[Worker] Job ${job?.id ?? 'unknown'} failed: ${err.message}`)
    // TODO: Send alert to user if repeated failures
  })

  worker.on('error', (err: Error) => {
    console.error(`[Worker] Worker error: ${err.message}`)
  })

  worker.on('stalled', (jobId: string) => {
    console.warn(`[Worker] Job ${jobId} stalled — will be retried`)
  })

  workerInstance = worker
  console.log('[Worker] Agent execution worker started')

  return worker
}

// ─── Graceful Shutdown ───────────────────────────────────────────────────────

export async function shutdownWorker(): Promise<void> {
  if (workerInstance) {
    console.log('[Worker] Shutting down worker...')
    await workerInstance.close()
    workerInstance = null
    console.log('[Worker] Worker shut down successfully')
  }
}

/**
 * Supabase Queries for Agent Credentials
 *
 * Handles secure storage/retrieval of encrypted credentials
 * All sensitive fields are encrypted before storage
 */

import { supabase, supabaseAdmin } from '@/lib/supabase/client'
import { encryptCredential, decryptCredential, generateWebhookToken } from '@/lib/credentials/vault'
import type { AgentCredentials } from '@/lib/credentials/vault'

// ─── Types ───────────────────────────────────────────────────────────────────

export interface StoredCredential {
  id: string
  user_id: string
  agent_id: string
  whatsapp_number?: string
  whatsapp_verified?: boolean
  website_url?: string
  website_verified?: boolean
  openai_api_key?: string // encrypted
  groq_api_key?: string // encrypted
  custom_ai_key?: string // encrypted
  custom_ai_provider?: 'openai' | 'groq' | 'gemini' | 'anthropic'
  auth_token?: string // encrypted
  webhook_url?: string
  created_at: string
  last_verified?: string
  last_rotated?: string
}

// ─── Create/Update Credentials ────────────────────────────────────────────────

/**
 * Store agent credentials (encrypts sensitive fields)
 */
export async function saveAgentCredentials(
  userId: string,
  agentId: string,
  creds: Partial<AgentCredentials>
): Promise<{ success: boolean; credentialId?: string; error?: string }> {
  try {
    const webhookUrl = `${process.env.NEXT_PUBLIC_APP_URL}/api/webhooks/whatsapp/${agentId}`
    const authToken = generateWebhookToken()

    const encryptedCreds: Record<string, unknown> = {
      user_id: userId,
      agent_id: agentId,
      whatsapp_number: creds.whatsapp_number,
      whatsapp_verified: false,
      website_url: creds.website_url,
      website_verified: creds.website_verified || false,
      custom_ai_provider: creds.custom_ai_provider,
      webhook_url: webhookUrl,
      auth_token: encryptCredential(authToken),
      created_at: new Date().toISOString(),
      last_verified: new Date().toISOString(),
    }

    // Encrypt sensitive API keys
    if (creds.openai_api_key) {
      encryptedCreds.openai_api_key = encryptCredential(creds.openai_api_key)
    }
    if (creds.groq_api_key) {
      encryptedCreds.groq_api_key = encryptCredential(creds.groq_api_key)
    }
    if (creds.custom_ai_key) {
      encryptedCreds.custom_ai_key = encryptCredential(creds.custom_ai_key)
    }

    // Use service role to bypass RLS for credential storage (highly secure)
    const { data, error } = await (supabaseAdmin.from('agent_credentials') as any)
      .upsert(encryptedCreds, {
        onConflict: 'agent_id',
      })
      .select('id')
      .single()

    if (error) {
      console.error('Failed to save credentials:', error)
      return { success: false, error: error.message }
    }

    return {
      success: true,
      credentialId: data?.id,
    }
  } catch (err) {
    console.error('Credential save error:', err)
    return { success: false, error: String(err) }
  }
}

// ─── Retrieve Credentials ────────────────────────────────────────────────────

/**
 * Get decrypted credentials for an agent
 * Only the owner (user) can retrieve their own credentials
 */
export async function getAgentCredentials(
  userId: string,
  agentId: string
): Promise<Partial<AgentCredentials> | null> {
  try {
    const { data, error } = await (supabase.from('agent_credentials') as any)
      .select('*')
      .eq('user_id', userId)
      .eq('agent_id', agentId)
      .single()

    if (error) {
      console.error('Failed to fetch credentials:', error)
      return null
    }

    if (!data) return null

    // Decrypt sensitive fields
    const decrypted: Partial<AgentCredentials> = {
      id: data.id,
      user_id: data.user_id,
      agent_id: data.agent_id,
      whatsapp_number: data.whatsapp_number,
      whatsapp_verified: data.whatsapp_verified,
      website_url: data.website_url,
      website_verified: data.website_verified,
      custom_ai_provider: data.custom_ai_provider,
      webhook_url: data.webhook_url,
      created_at: new Date(data.created_at),
      last_verified: data.last_verified ? new Date(data.last_verified) : undefined,
      last_rotated: data.last_rotated ? new Date(data.last_rotated) : undefined,
    }

    if (data.openai_api_key) {
      decrypted.openai_api_key = decryptCredential(data.openai_api_key)
    }
    if (data.groq_api_key) {
      decrypted.groq_api_key = decryptCredential(data.groq_api_key)
    }
    if (data.custom_ai_key) {
      decrypted.custom_ai_key = decryptCredential(data.custom_ai_key)
    }

    return decrypted
  } catch (err) {
    console.error('Error retrieving credentials:', err)
    return null
  }
}

/**
 * Get credentials using auth token (for webhook verification)
 * Does NOT decrypt keys - only used for webhook auth check
 */
export async function getCredentialsByAuthToken(
  agentId: string,
  authToken: string
): Promise<{ valid: boolean; userId?: string }> {
  try {
    const { data, error } = await (supabase.from('agent_credentials') as any)
      .select('user_id, auth_token')
      .eq('agent_id', agentId)
      .single()

    if (error || !data) {
      return { valid: false }
    }

    const storedToken = decryptCredential(data.auth_token)

    if (storedToken === authToken) {
      return { valid: true, userId: data.user_id }
    }

    return { valid: false }
  } catch (err) {
    console.error('Auth token verification failed:', err)
    return { valid: false }
  }
}

// ─── Update Credential Status ────────────────────────────────────────────────

/**
 * Mark credentials as verified (after successful test)
 */
export async function markCredentialsVerified(
  userId: string,
  agentId: string,
  fields: { whatsapp_verified?: boolean; website_verified?: boolean }
): Promise<boolean> {
  try {
    const update: Record<string, unknown> = {
      last_verified: new Date().toISOString(),
    }

    if (fields.whatsapp_verified !== undefined) {
      update.whatsapp_verified = fields.whatsapp_verified
    }
    if (fields.website_verified !== undefined) {
      update.website_verified = fields.website_verified
    }

    const { error } = await (supabase.from('agent_credentials') as any)
      .update(update)
      .eq('user_id', userId)
      .eq('agent_id', agentId)

    return !error
  } catch (err) {
    console.error('Failed to update credential status:', err)
    return false
  }
}

/**
 * Rotate API key (e.g., when user updates it)
 */
export async function rotateApiKey(
  userId: string,
  agentId: string,
  provider: 'openai' | 'groq' | 'custom',
  newKey: string
): Promise<boolean> {
  try {
    const update: Record<string, unknown> = {
      last_rotated: new Date().toISOString(),
    }

    if (provider === 'openai') {
      update.openai_api_key = encryptCredential(newKey)
    } else if (provider === 'groq') {
      update.groq_api_key = encryptCredential(newKey)
    } else {
      update.custom_ai_key = encryptCredential(newKey)
    }

    const { error } = await (supabase.from('agent_credentials') as any)
      .update(update)
      .eq('user_id', userId)
      .eq('agent_id', agentId)

    return !error
  } catch (err) {
    console.error('Failed to rotate API key:', err)
    return false
  }
}

// ─── Delete Credentials ───────────────────────────────────────────────────────

/**
 * Securely delete credentials (e.g., when agent is deleted)
 */
export async function deleteAgentCredentials(userId: string, agentId: string): Promise<boolean> {
  try {
    const { error } = await (supabase.from('agent_credentials') as any)
      .delete()
      .eq('user_id', userId)
      .eq('agent_id', agentId)

    return !error
  } catch (err) {
    console.error('Failed to delete credentials:', err)
    return false
  }
}

/**
 * Workflow Deployer — Orchestrates agent deployment
 *
 * When user deploys an agent:
 * 1. Save encrypted credentials
 * 2. Choose execution mode (LangGraph or n8n)
 * 3. Set up webhooks for incoming messages
 * 4. Activate the agent
 * 5. Return deployment status
 */

import { saveAgentCredentials } from '@/lib/supabase/credentials'
import type { AgentCredentials } from '@/lib/credentials/vault'

export interface DeploymentConfig {
  agentId: string
  userId: string
  agentName: string
  businessName: string
  industry: string
  websiteUrl?: string
  credentials: Partial<AgentCredentials>
  templateType: 'customer-support' | 'task-assignment' | 'appointment-booking' | 'lead-generator'
  executionMode: 'langgraph' | 'n8n' // LangGraph for simple, n8n for complex workflows
}

export interface DeploymentResult {
  success: boolean
  agentId: string
  webhookUrl?: string
  executionMode: string
  status: 'active' | 'pending' | 'error'
  message: string
  error?: string
  estimatedCost?: {
    setupCost: number // One-time setup
    monthlyCost: number // Recurring
    currency: string
  }
}

// ─── Deployment Orchestrator ────────────────────────────────────────────────

/**
 * Main deployment function
 * Coordinates credential storage, workflow setup, and activation
 */
export async function deployAgent(config: DeploymentConfig): Promise<DeploymentResult> {
  const startTime = Date.now()

  try {
    console.log(`[DEPLOY] Starting agent deployment: ${config.agentId}`)

    // Step 1: Validate credentials
    console.log(`[DEPLOY] Validating credentials...`)
    if (!config.credentials) {
      return {
        success: false,
        agentId: config.agentId,
        executionMode: 'langgraph',
        status: 'error',
        message: 'No credentials provided',
        error: 'Credentials are required for deployment',
      }
    }

    // Step 2: Save encrypted credentials to vault
    console.log(`[DEPLOY] Saving encrypted credentials...`)
    const credResult = await saveAgentCredentials(config.userId, config.agentId, config.credentials)

    if (!credResult.success) {
      return {
        success: false,
        agentId: config.agentId,
        executionMode: 'langgraph',
        status: 'error',
        message: 'Failed to save credentials',
        error: credResult.error,
      }
    }

    // Step 3: Deploy workflow based on execution mode
    let webhookUrl = ''
    let executionDetails = ''

    if (config.executionMode === 'langgraph') {
      console.log(`[DEPLOY] Setting up LangGraph execution...`)
      const langraphResult = await deployLangGraphAgent(config)
      if (!langraphResult.success) {
        return langraphResult
      }
      webhookUrl = langraphResult.webhookUrl || ''
      executionDetails = langraphResult.executionMode
    } else if (config.executionMode === 'n8n') {
      console.log(`[DEPLOY] Setting up n8n workflow...`)
      const n8nResult = await deployN8nWorkflow(config)
      if (!n8nResult.success) {
        return n8nResult
      }
      webhookUrl = n8nResult.webhookUrl || ''
      executionDetails = n8nResult.executionMode
    }

    // Step 4: Update agent status to "active"
    console.log(`[DEPLOY] Activating agent...`)
    const { supabase } = await import('@/lib/supabase/client')
    const { error: updateError } = await (supabase.from('agents') as any)
      .update({
        status: 'active',
        deployed_at: new Date().toISOString(),
        webhook_url: webhookUrl,
      })
      .eq('id', config.agentId)
      .eq('user_id', config.userId)

    if (updateError) {
      console.error('Failed to activate agent:', updateError)
      return {
        success: false,
        agentId: config.agentId,
        executionMode: 'langgraph',
        status: 'error',
        message: 'Failed to activate agent',
        error: updateError.message,
      }
    }

    // Step 5: Log deployment activity
    const { supabaseAdmin } = await import('@/lib/supabase/client')
    await (supabaseAdmin.from('activity_logs') as any).insert({
      user_id: config.userId,
      agent_id: config.agentId,
      action: 'agent_deployed_with_credentials',
      details: {
        templateType: config.templateType,
        executionMode: config.executionMode,
        webhookUrl,
        deploymentTimeMs: Date.now() - startTime,
      },
    })

    const durationSec = (Date.now() - startTime) / 1000
    console.log(`[DEPLOY] ✅ Deployment complete in ${durationSec.toFixed(2)}s`)

    return {
      success: true,
      agentId: config.agentId,
      webhookUrl,
      executionMode: executionDetails,
      status: 'active',
      message: `Agent deployed successfully using ${config.executionMode}`,
      estimatedCost: calculateDeploymentCost(config),
    }
  } catch (err) {
    console.error('[DEPLOY] Deployment failed:', err)
    return {
      success: false,
      agentId: config.agentId,
      executionMode: 'langgraph',
      status: 'error',
      message: 'Deployment failed',
      error: String(err),
    }
  }
}

// ─── Deployment Strategies ───────────────────────────────────────────────────

/**
 * Deploy using LangGraph (preferred for MVP)
 * Uses our existing executor with credentials
 */
async function deployLangGraphAgent(config: DeploymentConfig): Promise<DeploymentResult> {
  try {
    // LangGraph is already running in our Next.js app
    // We just need to:
    // 1. Inject credentials into the agent context
    // 2. Return the webhook URL (already generated in credentials step)

    const webhookUrl = `${process.env.NEXT_PUBLIC_APP_URL}/api/webhooks/whatsapp/${config.agentId}`

    console.log(`[LANGGRAPH] Agent ready at: ${webhookUrl}`)

    return {
      success: true,
      agentId: config.agentId,
      webhookUrl,
      executionMode: 'LangGraph (Real-time)',
      status: 'active',
      message: 'LangGraph agent deployed',
    }
  } catch (err) {
    return {
      success: false,
      agentId: config.agentId,
      executionMode: 'langgraph',
      status: 'error',
      message: 'Failed to deploy LangGraph agent',
      error: String(err),
    }
  }
}

/**
 * Deploy using n8n (for complex workflows)
 * Creates workflow from template and injects credentials
 */
async function deployN8nWorkflow(config: DeploymentConfig): Promise<DeploymentResult> {
  try {
    const n8nApiUrl = process.env.N8N_INSTANCE_URL || 'https://n8n.diyaa.ai'
    const n8nApiKey = process.env.N8N_API_KEY

    if (!n8nApiKey) {
      return {
        success: false,
        agentId: config.agentId,
        executionMode: 'n8n',
        status: 'error',
        message: 'n8n not configured',
        error: 'N8N_API_KEY not set',
      }
    }

    // Get template workflow (this would be stored in n8n or our DB)
    const templateId = getTemplateId(config.templateType)
    const webhookUrl = `${process.env.NEXT_PUBLIC_APP_URL}/api/webhooks/whatsapp/${config.agentId}`

    // Create workflow from template
    const createRes = await fetch(`${n8nApiUrl}/api/v1/workflows`, {
      method: 'POST',
      headers: {
        'X-N8N-API-KEY': n8nApiKey,
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({
        name: `${config.agentName} - ${config.agentId}`,
        nodes: buildWorkflowNodes(config, templateId),
        connections: buildWorkflowConnections(config, templateId),
        active: true,
        tags: ['diyaa-deployed', config.templateType],
      }),
    })

    if (!createRes.ok) {
      throw new Error(`Failed to create n8n workflow: ${createRes.statusText}`)
    }

    const workflow = (await createRes.json()) as { id: string; name: string }
    console.log(`[N8N] Workflow created: ${workflow.id}`)

    // Activate workflow
    const activateRes = await fetch(`${n8nApiUrl}/api/v1/workflows/${workflow.id}`, {
      method: 'PATCH',
      headers: {
        'X-N8N-API-KEY': n8nApiKey,
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({ active: true }),
    })

    if (!activateRes.ok) {
      throw new Error(`Failed to activate workflow: ${activateRes.statusText}`)
    }

    return {
      success: true,
      agentId: config.agentId,
      webhookUrl,
      executionMode: `n8n (Workflow ${workflow.id})`,
      status: 'active',
      message: 'n8n workflow deployed',
    }
  } catch (err) {
    return {
      success: false,
      agentId: config.agentId,
      executionMode: 'n8n',
      status: 'error',
      message: 'Failed to deploy n8n workflow',
      error: String(err),
    }
  }
}

